class PerformanceMetrics:
    """Collect and analyze performance metrics."""

    def __init__(self):
        self.response_times: list[float] = []
        self.successful_requests = 0
        self.failed_requests = 0
        self.start_time = None
        self.end_time = None

    def start_timing(self):
        """Start the timing measurement."""
        self.start_time = time.time()

    def end_timing(self):
        """End the timing measurement."""
        self.end_time = time.time()

    def record_request(self, response_time: float, success: bool):
        """Record a single request result."""
        self.response_times.append(response_time)
        if success:
            self.successful_requests += 1
        else:
            self.failed_requests += 1

    @property
    def total_requests(self) -> int:
        return self.successful_requests + self.failed_requests

    @property
    def success_rate(self) -> float:
        if self.total_requests == 0:
            return 0.0
        return self.successful_requests / self.total_requests

    @property
    def requests_per_second(self) -> float:
        if not self.start_time or not self.end_time:
            return 0.0
        duration = self.end_time - self.start_time
        return self.total_requests / duration if duration > 0 else 0.0

    @property
    def avg_response_time(self) -> float:
        return np.mean(self.response_times) if self.response_times else 0.0

    @property
    def p95_response_time(self) -> float:
        if not self.response_times:
            return 0.0
        return np.percentile(self.response_times, 95)

    @property
    def p99_response_time(self) -> float:
        if not self.response_times:
            return 0.0
        return np.percentile(self.response_times, 99)


class RawJsonRpcClient:
    """Raw socket JSON-RPC client for direct server performance testing."""

    def __init__(
        self,
        transport: str,
        host: str = "127.0.0.1",
        port: int | None = None,
        socket_path: str | None = None,
    ):
        self.transport = transport
        self.host = host
        self.port = port
        self.socket_path = socket_path
        self._reader = None
        self._writer = None

        # Pre-prepared requests
        self._get_mining_info_request = (
            json.dumps({"jsonrpc": "2.0", "method": "getMiningInfo", "params": [], "id": 1}) + "\n"
        )

        sample_plain_proof = _create_sample_plain_proof_for_performance()

        submit_plain_proof_params = {
            "plain_proof": sample_plain_proof.to_base64(),
            "mining_job": {
                "incomplete_header_bytes": "AAAAIDhiU/6qm0m0dHuhR3D/4amWtlumgYWBWHROIlcW1ln7CH+YUAYaAOJx8e9+e/LT+8Crf85o3D8eDKcHVk0PLvP3ZF5p//8PHQAAAAAAAAAA",
                "target": 431358735298270906413161702650018451440568065076682751302691926835200,
            },
        }

        self._submit_plain_proof_request = (
            json.dumps(
                {
                    "jsonrpc": "2.0",
                    "method": "submitPlainProof",
                    "params": submit_plain_proof_params,
                    "id": 2,
                }
            )
            + "\n"
        )

    async def __aenter__(self):
        await self.connect()
        return self

    async def __aexit__(self, exc_type, exc_val, exc_tb):
        await self.close()

    async def connect(self):
        """Establish connection to the server."""
        # Use the same buffer limit as the server (1MB) to handle large responses
        buffer_limit = 2**20
        if self.transport == "tcp":
            self._reader, self._writer = await asyncio.open_connection(
                self.host, self.port, limit=buffer_limit
            )
        else:  # UDS
            self._reader, self._writer = await asyncio.open_unix_connection(
                self.socket_path, limit=buffer_limit
            )

    async def close(self):
        """Close the connection."""
        if self._writer:
            self._writer.close()
            await self._writer.wait_closed()
            self._writer = None
            self._reader = None

    async def send_raw_request(self, request_data: str) -> tuple[float, bool]:
        """Send a raw JSON-RPC request and measure response time."""
        if not self._writer:
            raise RuntimeError("Not connected")

        start_time = time.time()

        try:
            # Send request
            self._writer.write(request_data.encode())
            await self._writer.drain()

            # Read response
            response_line = await self._reader.readline()
            response_time = time.time() - start_time

            # Parse response to check if it's valid
            if response_line:
                try:
                    response = json.loads(response_line.decode().strip())
                    success = "result" in response or "error" in response
                except json.JSONDecodeError:
                    success = False
            else:
                success = False

            return response_time, success

        except Exception:
            response_time = time.time() - start_time
            return response_time, False

    async def send_get_mining_info(self) -> tuple[float, bool]:
        """Send getMiningInfo request."""
        return await self.send_raw_request(self._get_mining_info_request)

    async def send_submit_plain_proof(self) -> tuple[float, bool]:
        """Send submitPlainProof request."""
        return await self.send_raw_request(self._submit_plain_proof_request)


