def create_raw_client(config: MinerRpcConfig):
    """Create a RawJsonRpcClient based on transport configuration."""
    if config.transport == "tcp":
        return RawJsonRpcClient(transport="tcp", port=config.port)
    else:  # UDS
        return RawJsonRpcClient(transport="uds", socket_path=config.socket_path)


@pytest.mark.performance
class TestMinerRpcPerformanceThroughput:
    """Test throughput performance under various conditions."""

    async def test_sequential_throughput(self, performance_server):
        """Measure throughput with sequential requests."""
        server, config = performance_server
        metrics = PerformanceMetrics()
        num_requests = 50000

        async with create_raw_client(config) as client:
            metrics.start_timing()

            for _ in range(num_requests):
                response_time, success = await client.send_get_mining_info()
                metrics.record_request(response_time, success)

            metrics.end_timing()

        # Assert performance requirements
        assert metrics.success_rate >= 0.99, f"Success rate too low: {metrics.success_rate}"
        assert metrics.requests_per_second >= 9000, (
            f"Throughput too low: {metrics.requests_per_second} RPS"
        )
        assert metrics.avg_response_time <= 0.002, (
            f"Average response time too high: {metrics.avg_response_time}s"
        )
        assert metrics.p95_response_time <= 0.01, (
            f"P95 response time too high: {metrics.p95_response_time}s"
        )

        print(f"Sequential throughput ({config.transport}): {metrics.requests_per_second:.1f} RPS")
        print(f"Average response time: {metrics.avg_response_time * 1000:.2f}ms")
        print(f"P95 response time: {metrics.p95_response_time * 1000:.2f}ms")

    async def test_concurrent_throughput(self, performance_server):
        """Measure throughput with concurrent requests."""
        server, config = performance_server
        metrics = PerformanceMetrics()
        num_concurrent = 50
        requests_per_client = 100

        # Create and connect all clients first
        clients = []
        for _ in range(num_concurrent):
            client = create_raw_client(config)
            await client.connect()
            clients.append(client)

        try:

            async def client_worker(client):
                """Worker function for each concurrent client."""
                for _ in range(requests_per_client):
                    response_time, success = await client.send_get_mining_info()
                    metrics.record_request(response_time, success)

            metrics.start_timing()

            # Create concurrent tasks using pre-connected clients
            tasks = [client_worker(client) for client in clients]
            await asyncio.gather(*tasks)

            metrics.end_timing()

        finally:
            # Clean up all clients
            for client in clients:
                await client.close()

        total_requests = num_concurrent * requests_per_client

        # Assert performance requirements for concurrent load
        assert metrics.success_rate >= 0.95, (
            f"Success rate too low under load: {metrics.success_rate}"
        )
        assert metrics.requests_per_second >= 10000, (
            f"Concurrent throughput too low: {metrics.requests_per_second} RPS"
        )
        assert metrics.p99_response_time <= 0.01, (
            f"P99 response time too high under load: {metrics.p99_response_time}s"
        )

        print(f"Concurrent throughput ({config.transport}): {metrics.requests_per_second:.1f} RPS")
        print(f"Total requests: {total_requests}")
        print(f"Success rate: {metrics.success_rate:.3f}")


@pytest.mark.performance
class TestMinerRpcPerformanceLatency:
    """Test latency characteristics under different conditions."""

    async def test_baseline_latency(self, performance_server):
        """Measure baseline latency with minimal load."""
        server, config = performance_server
        metrics = PerformanceMetrics()

        async with create_raw_client(config) as client:
            # Warm up
            for _ in range(10):
                await client.send_get_mining_info()

            # Measure baseline
            for _ in range(100):
                response_time, success = await client.send_get_mining_info()
                metrics.record_request(response_time, success)

        # Baseline should be very fast
        assert metrics.avg_response_time <= 0.002, (
            f"Baseline latency too high: {metrics.avg_response_time * 1000:.2f}ms"
        )
        assert metrics.p95_response_time <= 0.005, (
            f"Baseline P95 too high: {metrics.p95_response_time * 1000:.2f}ms"
        )

        print(
            f"Baseline average latency ({config.transport}): {metrics.avg_response_time * 1000:.2f}ms"
        )
        print(f"Baseline P95 latency: {metrics.p95_response_time * 1000:.2f}ms")

    async def test_latency_under_load(self, performance_server):
        """Measure latency degradation under load."""
        server, config = performance_server
        metrics = PerformanceMetrics()

        # Create background load
        async def background_load():
            async with create_raw_client(config) as client:
                while True:
                    try:
                        await client.send_get_mining_info()
                        await asyncio.sleep(0.001)  # 1ms between requests
                    except asyncio.CancelledError:
                        break
                    except Exception:
                        pass

        # Start background load
        background_tasks = [asyncio.create_task(background_load()) for _ in range(10)]

        try:
            # Wait for load to build up
            await asyncio.sleep(1)

            # Measure latency under load
            async with create_raw_client(config) as client:
                for _ in range(100):
                    response_time, success = await client.send_get_mining_info()
                    metrics.record_request(response_time, success)

        finally:
            # Stop background load
            for task in background_tasks:
                task.cancel()
            await asyncio.gather(*background_tasks, return_exceptions=True)

        # Latency should still be reasonable under load
        assert metrics.avg_response_time <= 0.01, (
            f"Latency under load too high: {metrics.avg_response_time * 1000:.2f}ms"
        )
        assert metrics.p95_response_time <= 0.02, (
            f"P95 under load too high: {metrics.p95_response_time * 1000:.2f}ms"
        )

        print(
            f"Latency under load average ({config.transport}): {metrics.avg_response_time * 1000:.2f}ms"
        )
        print(f"Latency under load P95: {metrics.p95_response_time * 1000:.2f}ms")


