@pytest.mark.performance
@pytest.mark.slow
class TestMinerRpcPerformanceLongRunning:
    """Long-running performance and stability tests."""

    async def test_sustained_load_stability(self, performance_server):
        """Test stability under sustained load for extended period."""
        server, config = performance_server
        metrics = PerformanceMetrics()
        duration_seconds = 60  # 1 minute test
        target_rps = 8000  # Conservative target for sustained load

        async def sustained_load_worker():
            """Worker that maintains sustained load."""
            request_interval = 1.0 / target_rps

            async with create_raw_client(config) as client:
                while True:
                    response_time, success = await client.send_get_mining_info()
                    metrics.record_request(response_time, success)

                    # Maintain target rate
                    sleep_time = max(0, request_interval / 2 - response_time)
                    if sleep_time > 0.001:  # Only sleep if the duration is meaningful (> 1ms)
                        await asyncio.sleep(sleep_time)

        # Start sustained load
        metrics.start_timing()
        task = asyncio.create_task(sustained_load_worker())

        try:
            # Run for specified duration
            await asyncio.sleep(duration_seconds)

        finally:
            task.cancel()
            with contextlib.suppress(asyncio.CancelledError):
                await task

        metrics.end_timing()

        # Should maintain stable performance
        assert metrics.success_rate >= 0.98, (
            f"Sustained load success rate too low: {metrics.success_rate}"
        )

        expected_requests = duration_seconds * target_rps
        actual_requests = metrics.total_requests
        throughput_ratio = actual_requests / expected_requests

        assert throughput_ratio >= 0.9, f"Sustained throughput too low: {throughput_ratio:.2f}"

        print(f"Sustained load ({config.transport}) - Duration: {duration_seconds}s")
        print(f"Expected requests: {expected_requests}, Actual: {actual_requests}")
        print(f"Success rate: {metrics.success_rate:.3f}")
        print(f"Average response time: {metrics.avg_response_time * 1000:.2f}ms")


